// ═══════════════════════════════════════════════════════
// NEORA ADS — Validation & Extraction des paramètres
// ═══════════════════════════════════════════════════════

const input = $input.first().json;
const b = input.body ?? input;

// === Paramètres requis ===
const promptUser = (b.prompt_user ?? "").toString().trim();
if (!promptUser) throw new Error("Missing prompt_user");

// === Images (multi-images support) ===
let imageUrls = [];
if (b.image_urls && Array.isArray(b.image_urls)) {
  imageUrls = b.image_urls.filter(url => url && url.trim() !== "");
} else if (b.image_url && b.image_url.trim() !== "") {
  imageUrls = [b.image_url.trim()];
}

// === Template ADS ===
// Valeurs possibles : lifestyle, packshot, avant_apres, ugc, custom
const template = (b.template ?? "custom").toString().trim().toLowerCase();

// === Paramètres optionnels ===
const resolution = (b.resolution ?? "2K").toString().trim();
const aspectRatio = (b.aspectRatio ?? "1:1").toString().trim();
const brand = (b.brand ?? "").toString().trim();
const productName = (b.product_name ?? "").toString().trim();

// === Overlay (optionnel) ===
const overlayEnabled = b.overlay === true || b.overlay === "true";
const overlayText = (b.overlay_text ?? "").toString().trim();
const overlayPosition = (b.overlay_position ?? "bottom").toString().trim(); // top, center, bottom
const overlayStyle = (b.overlay_style ?? "modern").toString().trim(); // modern, bold, minimal

return [{ json: {
  promptUser,
  imageUrls,
  template,
  resolution,
  aspectRatio,
  brand,
  productName,
  overlayEnabled,
  overlayText,
  overlayPosition,
  overlayStyle
}}];

// ═══════════════════════════════════════════════════════
// NEORA ADS — Template Engine
// Enrichit le prompt selon le template sélectionné
// + Traduction FR → EN intégrée
// ═══════════════════════════════════════════════════════

const data = $input.first().json;
const { promptUser, template, brand, productName } = data;

// ── Détection langue FR (basique mais efficace) ──
const frenchWords = ["une", "pour", "avec", "dans", "sur", "les", "des", "est", "créer", "faire", "pub", "produit", "marque", "naturel", "soin", "beauté", "huile", "crème", "bien-être"];
const words = promptUser.toLowerCase().split(/\s+/);
const isFrench = frenchWords.some(fw => words.includes(fw));

// ── Templates de prompt ads ──
const TEMPLATES = {
  lifestyle: {
    prefix: "Professional advertising photography, lifestyle scene,",
    suffix: "warm natural lighting, authentic moment, bokeh background, editorial quality, 8K ultra-detailed, commercial photography, aspirational mood, soft color palette",
    negativeHints: "no text, no watermark, no logo overlay"
  },
  packshot: {
    prefix: "Professional product packshot photography, studio setup,",
    suffix: "clean white or gradient background, perfect studio lighting, product centered, sharp focus on product details, commercial grade, reflection on surface, 8K ultra-detailed, catalog quality",
    negativeHints: "no distractions, no text, no watermark"
  },
  avant_apres: {
    prefix: "Professional before and after comparison photography, split view,",
    suffix: "clinical lighting, same angle both sides, clear transformation visible, professional medical/beauty advertising style, high contrast, 8K ultra-detailed, convincing results",
    negativeHints: "no text overlay, no fake effects"
  },
  ugc: {
    prefix: "User-generated content style photo, authentic social media aesthetic,",
    suffix: "smartphone camera quality, natural imperfect lighting, genuine and relatable, casual setting, Instagram-worthy, warm tones, slight grain, real person using product, candid moment",
    negativeHints: "no studio look, no over-processed"
  },
  custom: {
    prefix: "Professional commercial photography,",
    suffix: "high quality, 8K ultra-detailed, advertising grade",
    negativeHints: "no watermark"
  }
};

const tpl = TEMPLATES[template] || TEMPLATES.custom;

// ── Construction du prompt enrichi ──
let enrichedParts = [tpl.prefix];

// Ajout contexte marque/produit si fourni
if (brand) enrichedParts.push(`brand: ${brand},`);
if (productName) enrichedParts.push(`product: ${productName},`);

// Ajout du prompt utilisateur
enrichedParts.push(promptUser + ",");

// Ajout du suffix template
enrichedParts.push(tpl.suffix);

let finalPrompt = enrichedParts.join(" ").replace(/,\s*,/g, ",").replace(/,\s*$/, "");

// ── Traduction FR → EN (mapping courant) ──
if (isFrench) {
  const translations = {
    "créer une pub": "create an advertisement",
    "créer": "create",
    "pub": "advertisement",
    "produit": "product",
    "sur fond": "on background",
    "fond blanc": "white background",
    "fond noir": "black background",
    "fond naturel": "natural background",
    "avec": "with",
    "pour": "for",
    "huile": "oil",
    "crème": "cream",
    "soin": "skincare",
    "beauté": "beauty",
    "naturel": "natural",
    "bien-être": "wellness",
    "visage": "face",
    "corps": "body",
    "cheveux": "hair",
    "massage": "massage",
    "tropical": "tropical",
    "exotique": "exotic",
    "tahitien": "Tahitian",
    "polynésien": "Polynesian",
    "monoï": "monoi",
    "tamanu": "tamanu",
    "noix de coco": "coconut",
    "coco": "coconut",
    "fleur": "flower",
    "plante": "plant",
    "ingrédient": "ingredient",
    "ingrédients": "ingredients",
    "mis en scène": "staged scene",
    "mise en scène": "staged scene",
    "élégant": "elegant",
    "luxueux": "luxurious",
    "premium": "premium",
    "moderne": "modern",
    "minimaliste": "minimalist",
    "une femme": "a woman",
    "un homme": "a man",
    "une personne": "a person",
    "dans la nature": "in nature",
    "sur la plage": "on the beach",
    "plage": "beach",
    "lagon": "lagoon",
    "mer": "sea",
    "palmier": "palm tree"
  };

  // Remplacement des termes FR par EN dans le prompt user
  let translatedPrompt = finalPrompt;
  // Trier par longueur décroissante pour éviter les remplacements partiels
  const sortedKeys = Object.keys(translations).sort((a, b) => b.length - a.length);
  for (const fr of sortedKeys) {
    const regex = new RegExp(fr, "gi");
    translatedPrompt = translatedPrompt.replace(regex, translations[fr]);
  }
  finalPrompt = translatedPrompt;
}

// ── Nettoyage final ──
finalPrompt = finalPrompt
  .replace(/\s+/g, " ")
  .replace(/,\s*,/g, ",")
  .trim();

// ═══════════════════════════════════════════════════════
// 🔒 PRODUCT PRESERVATION LOGIC
// Si des images sont uploadées ET l'utilisateur ne demande PAS
// de modifier le produit lui-même, on ajoute des instructions
// strictes de préservation pour que l'IA ne touche qu'à
// la mise en scène / le décor / l'éclairage.
// ═══════════════════════════════════════════════════════

const hasImages = data.imageUrls.length > 0;

// Mots-clés qui indiquent que l'utilisateur VEUT modifier le produit
// (dans ce cas on ne force PAS la préservation)
const modifyProductKeywords = [
  // FR
  "modifie le produit", "change le produit", "transforme le produit",
  "change la couleur du produit", "nouveau packaging", "nouvelle étiquette",
  "change l'étiquette", "modifie l'étiquette", "change le flacon",
  "change la bouteille", "redesign", "refais le produit",
  "remplace le produit", "change le label", "modifie le label",
  // EN
  "modify the product", "change the product", "transform the product",
  "new packaging", "new label", "redesign the product", "replace the product",
  "change product color", "modify the bottle", "change the bottle"
];

const lowerPrompt = promptUser.toLowerCase();
const userWantsToModifyProduct = modifyProductKeywords.some(kw =>
  lowerPrompt.includes(kw)
);

if (hasImages && !userWantsToModifyProduct) {
  // 🔒 INJECTION DES INSTRUCTIONS DE PRÉSERVATION
  const preservationPrefix = "CRITICAL INSTRUCTION: Preserve the uploaded product image EXACTLY as it is. Do NOT modify, alter, redesign, or change the product itself in any way. Keep the product's exact shape, colors, label, packaging, text, logo, and all visual details 100% identical to the source image. Only modify the surrounding environment, background, lighting, scene composition, and atmosphere. The product must remain pixel-perfect identical. ";

  const preservationSuffix = ", IMPORTANT: the product itself must be preserved exactly as shown in the source image - same shape, same label, same colors, same text, same packaging - only the background and scene around it should be changed";

  finalPrompt = preservationPrefix + finalPrompt + preservationSuffix;
}

return [{ json: {
  ...data,
  finalPrompt,
  template,
  hasImages,
  productPreserved: hasImages && !userWantsToModifyProduct,
  userWantsToModifyProduct
}}];

