// ═══════════════════════════════════════════════════════
// NEORA ADS — Overlay Text sur Image
// Utilise l'API fal.ai pour ajouter du texte promo
// en re-générant avec le texte intégré au prompt
// ═══════════════════════════════════════════════════════

const input = $input.first().json;
const imageUrl = input.images?.[0]?.url ?? "";

// Récupérer les params overlay depuis le workflow
// On remonte dans la chaîne pour trouver les données originales
const overlayText = input.overlayText ?? $('Template Engine + FR→EN').first().json.overlayText ?? "";
const overlayPosition = input.overlayPosition ?? $('Template Engine + FR→EN').first().json.overlayPosition ?? "bottom";
const overlayStyle = input.overlayStyle ?? $('Template Engine + FR→EN').first().json.overlayStyle ?? "modern";
const brand = input.brand ?? $('Template Engine + FR→EN').first().json.brand ?? "";

if (!imageUrl) throw new Error("No image URL from generation");
if (!overlayText) throw new Error("Overlay enabled but no overlay_text provided");

// ── Style mapping ──
const styles = {
  modern: "sleek modern sans-serif typography, clean white text with subtle shadow, professional advertising layout",
  bold: "bold impactful typography, large uppercase letters, high contrast text, attention-grabbing headline style",
  minimal: "minimal elegant thin typography, understated text, luxury brand aesthetic, whisper-quiet lettering"
};

const positions = {
  top: "text positioned at the top of the image",
  center: "text centered in the middle of the image",
  bottom: "text positioned at the bottom of the image"
};

// ── Prompt pour overlay ──
let overlayPrompt = `Add promotional text overlay to this image. Text: "${overlayText}"`;
if (brand) overlayPrompt += `, brand: ${brand}`;
overlayPrompt += `. ${styles[overlayStyle] || styles.modern}, ${positions[overlayPosition] || positions.bottom}`;
overlayPrompt += ", do not change the product or background, only add text overlay";

return [{ json: {
  overlayPrompt,
  generatedImageUrl: imageUrl,
  overlayText,
  overlayPosition,
  overlayStyle
}}];

